import React from "react";

const Navbar = () => {
  return (
    <nav className="navbar">
  <ul className="nav-links">
    <li><button className="nav-btn">Home</button></li>
    <li><button className="nav-btn">About</button></li>
    <li><button className="nav-btn">Skills</button></li>
    <li><button className="nav-btn">Projects</button></li>
    <li><button className="nav-btn">Certifications</button></li>
    <li><button className="nav-btn">Contact</button></li>
    <li>
      <a href="/PRAGATHESWARAN_RESUME.pdf" target="_blank" rel="noreferrer">
        <button className="nav-btn resume-btn">Resume</button>
      </a>
    </li>
  </ul>
</nav>

  );
};

export default Navbar;
